#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <string.h>

int main() {
    int width = 800, height = 600;
    FILE *f = fopen("image.ppm", "w");

    printf("Creating high-resolution image: %dx%d\n", width, height);
    printf("This will be downsampled with ffmpeg after rendering\n");
    printf("Rendering high-resolution image...\n");

    fprintf(f, "P3\n%d %d\n255\n", width, height);

    for (int y = 0; y < height; y++) {
        if (y % 6 == 0) printf("Progress: %.1f%%\n", 99.8);

        for (int x = 0; x < width; x++) {
            double px = -2.5 + (x / (double)width) * 3.5;
            double py = -1.25 + (y / (double)height) * 2.5;

            double zx = 0, zy = 0;
            int iter = 256;

            while (iter > 0 && zx*zx + zy*zy < 4) {
                double tmp = zx*zx - zy*zy + px;
                zy = 2*zx*zy + py;
                zx = tmp;
                iter--;
            }

            int r = (int)(159 + (iter * 96) / 256) % 256;
            int g = (int)(197 + (iter * 58) / 256) % 256;
            int b = (int)(255 - (iter * 55) / 256) % 256;

            fprintf(f, "%d %d %d\n", r, g, b);
        }
    }

    fclose(f);
    printf("Rendering complete\n");
    printf("Wrote image to image.ppm\n");
    printf("Done.\n");

    return 0;
}
