                g = (int)(195 + 15*diff - 4*u*u - 2*v*v);
                b = (int)(170 + 20*diff + 5*u*u + 4*v*v);
            } else {
                r = 150 - (int)(15*r_sq);
                g = 190 - (int)(8*r_sq);
                b = 210 - (int)(12*r_sq);
            }

            if (r < 0) r = 0; if (r > 255) r = 255;
            if (g < 0) g = 0; if (g > 255) g = 255;
            if (b < 0) b = 0; if (b > 255) b = 255;

            fprintf(f, "%d %d %d\n", r, g, b);
        }
    }

    fclose(f);
    printf("Rendering complete\n");
